class Solution {
    public int maximumLength(String s) {
        int count = 0;
        int maxLength = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j < s.length(); j++) {
                if (s.charAt(i) == s.charAt(j)) {
                    count++;
                    if (count > maxLength) {
                        maxLength = count;
                    }
                }
            }
        }
        return maxLength;
    }
}
```

